window.docContents[221].resolve({"/Viewing-the-Output/#Zippers___-A-Documentation-Example--Viewing-the-Output":{"contents":"Verso's HTML doesn't presently work correctly when opened directly in a browser, so it should be served via a server.This is due to security restrictions on retrieved files: some of the code hovers are deduplicated to a JSON file that's fetched on demand.\nPython has a simple web server module that's useful for this; however, it tends to send cache control headers that prevent some content from being refreshed.\n\nIn the root of this source repository, there is a serve.py script that sends more appropriate headers.\nTo use it, run python3 serve.py 8000 -d DIR to serve the files in DIR on http://localhost:8000.\nThe port and root can be customized by modifying the appropriate command-line options.\n\n","context":"Zippers: A Documentation Example","header":"6. Viewing the Output","id":"/Viewing-the-Output/#Zippers___-A-Documentation-Example--Viewing-the-Output"}});